mapper.select:
SELECT p.*, (SELECT COUNT(1) FROM forum_like fl WHERE fl.post_id = p.id) AS like_count, CASE WHEN #{currentUserId} IS NULL THEN 0 WHEN EXISTS (SELECT 1 FROM forum_like fl2 WHERE fl2.post_id = p.id AND fl2.user_id = #{currentUserId}) THEN 1 ELSE 0 END AS liked, (SELECT COUNT(1) FROM forum_favorite ff WHERE ff.post_id = p.id) AS favorite_count, CASE WHEN #{currentUserId} IS NULL THEN 0 WHEN EXISTS (SELECT 1 FROM forum_favorite ff2 WHERE ff2.post_id = p.id AND ff2.user_id = #{currentUserId}) THEN 1 ELSE 0 END AS favorited, CASE WHEN p.is_anonymous = 1 THEN '匿名用户' ELSE u.nickname END AS user_nickname, CASE WHEN p.is_anonymous = 1 THEN '' ELSE u.avatar END AS user_avatar, s.name_zh AS school_name FROM forum_post p LEFT JOIN sys_user u ON p.user_id = u.id LEFT JOIN school s ON p.school_id = s.id WHERE p.deleted = 0
AND p.category = #{category}
AND p.school_id = #{schoolId}
AND p.is_school_only = 0
ORDER BY (p.comment_count + p.view_count + (SELECT COUNT(1) FROM forum_like fl3 WHERE fl3.post_id = p.id)) DESC, p.create_time DESC
ORDER BY p.create_time DESC
